const JAVA_KIND_PATTERNS = [
  ['intro', /(what is java|introduction to java)/i],
  ['history', /(history of java)/i],
  ['features', /(features of java)/i],
  ['applications', /(applications of java)/i],
  ['jdk', /(jdk|java development kit)/i],
  ['jre', /(jre|java runtime environment)/i],
  ['jvm', /(jvm|java virtual machine)/i],
  ['setup', /(installation|setup|environment|ide)/i],
  ['first_program', /(first java program)/i],
  ['variables', /(variables)/i],
  ['data_types', /(data types|type casting|literals)/i],
  ['operators', /(operators)/i],
  ['io', /(user input|scanner)/i],
  ['comments', /(comments)/i],
  ['keywords', /(keywords)/i],
  ['conditionals', /(if |if-else|nested if|switch|ternary)/i],
  ['loops', /(for loop|while loop|do-while|break|continue)/i],
  ['methods', /(methods|parameters|return types|overloading)/i],
  ['arrays', /(arrays|multi-dimensional|enhanced for|array util)/i],
  ['classes', /(classes|objects|constructors)/i],
  ['oop_keywords', /(this|static|instance|local|access modifiers)/i],
  ['encapsulation', /(encapsulation)/i],
  ['inheritance', /(inheritance)/i],
  ['polymorphism', /(polymorphism|overriding)/i],
  ['abstraction', /(abstraction|abstract|interfaces)/i],
  ['object_class', /(object class)/i],
  ['strings', /(string|stringbuilder|stringbuffer|regex)/i],
  ['exceptions', /(exception|try|catch|finally|throw)/i],
  ['packages', /(packages|import|wrapper|math|random|date|utility)/i],
  ['collections', /(collections|list|arraylist|linkedlist|vector|stack|set|hashset|treeset|queue|map|hashmap|treemap|iterator|comparable|comparator)/i],
  ['files', /(file|inputstream|outputstream|buffered|reader|writer|serialization|nio)/i],
  ['threads', /(thread|runnable|synchronization|deadlock|executor|callable|future|concurrent)/i],
  ['generics', /(generics|enums|annotations|reflection|inner|nested|records|sealed|var)/i],
  ['lambdas', /(lambda|stream|optional|function|predicate|consumer|supplier)/i],
  ['sql', /(sql|database|dbms|rdbms|mysql|table|constraint|crud|join|group|order|aggregate|subquery|view|index)/i],
  ['jdbc', /(jdbc|drivermanager|connection|statement|preparedstatement|resultset|transaction|batch|pooling)/i],
  ['git', /(git|version control|repository|commit|branch|merge|rebase|pull request)/i],
  ['spring', /(spring|ioc|dependency injection|bean|mvc|validation)/i],
  ['spring_boot', /(spring boot|starter|auto-configuration|rest api|request mapping|logging|config)/i],
  ['backend', /(jpa|hibernate|entity|repository|service|dto|pagination|swagger|jwt|security|redis|kafka|docker|microservices|gateway|discovery)/i],
  ['testing', /(test|junit|mockito|postman|ci\/cd|github actions|maven|deploy|monitoring)/i],
  ['project', /(project:)/i],
  ['general', /.*/],
];

const inferJavaKind = (title = '') => {
  const match = JAVA_KIND_PATTERNS.find(([, pattern]) => pattern.test(title));
  return match ? match[0] : 'general';
};

const getJavaSyntaxForTopic = (title) => {
  const syntaxMap = {
    'What is Java?': `public class Main {\n    public static void main(String[] args) {\n        System.out.println("Hello from Java!");\n    }\n}`,
    'History of Java': `// Java version history\nString[] versions = {"JDK 1.0", "JDK 1.1", "J2SE 1.2", "Java 5", "Java 8", "Java 11", "Java 17", "Java 21"};\nfor (String version : versions) {\n    System.out.println(version);\n}`,
    'Features of Java': `// Key features of Java\nString[] features = {"Platform Independent", "Object-Oriented", "Secure", "Multithreaded", "Robust"};\nfor (int i = 0; i < features.length; i++) {\n    System.out.println((i + 1) + ". " + features[i]);\n}`,
    'Applications of Java': `// Applications of Java\nString[][] apps = {{\"Android\", \"Mobile apps\"}, {\"Web\", \"Enterprise web\"}, {\"IoT\", \"Smart devices\"}};\nfor (String[] app : apps) {\n    System.out.println(app[0] + ": " + app[1]);\n}`,
    'JDK': `// Verify JDK installation\npublic class JDKCheck {\n    public static void main(String[] args) {\n        System.out.println("Java Version: " + System.getProperty("java.version"));\n        System.out.println("Java Home: " + System.getProperty("java.home"));\n    }\n}`,
    'JRE': `// JRE components\npublic class JREComponents {\n    public static void main(String[] args) {\n        String[] components = {"ClassLoader", "Bytecode Verifier", "Runtime Libraries"};\n        for (String c : components) {\n            System.out.println("JRE Component: " + c);\n        }\n    }\n}`,
    'JVM': `// JVM architecture info\npublic class JVMInfo {\n    public static void main(String[] args) {\n        Runtime rt = Runtime.getRuntime();\n        System.out.println("Available Processors: " + rt.availableProcessors());\n        System.out.println("Total Memory: " + rt.totalMemory() / 1024 / 1024 + " MB");\n    }\n}`,
    'Java Installation': `// Verify Java installation\npublic class VerifyJava {\n    public static void main(String[] args) {\n        String version = System.getProperty("java.version");\n        if (version != null && !version.isEmpty()) {\n            System.out.println("Java is installed. Version: " + version);\n        } else {\n            System.out.println("Java is not detected.");\n        }\n    }\n}`,
    'IDE Setup': `// IDE setup verification\npublic class FirstProject {\n    public static void main(String[] args) {\n        System.out.println("Project Name: CS Studio Java");\n        System.out.println("IDE: Configured Successfully");\n        System.out.println("Ready to code!");\n    }\n}`,
    'First Java Program': `// Every Java program needs:\n// 1. A class declaration (name matches filename)\n// 2. A main method (program entry point)\n// 3. Statements inside the method\n\npublic class Main {\n    public static void main(String[] args) {\n        System.out.println("Text to display");\n    }\n}`,
  };

  if (syntaxMap[title]) return syntaxMap[title];

  const defaults = {
    intro: `public class Main {\n    public static void main(String[] args) {\n        System.out.println("Learn Java with CS Studio");\n    }\n}`,
    history: `String[] history = {"1995: Java created", "1996: JDK 1.0", "2004: Java 5", "2014: Java 8", "2021: Java 17"};\nfor (String h : history) { System.out.println(h); }`,
    features: `String[] features = {"Simple", "Secure", "Portable", "Object-Oriented", "Multithreaded"};\nfor (String f : features) { System.out.println(f); }`,
    applications: `String[] apps = {"Android", "Web Apps", "Enterprise SW", "Big Data", "IoT"};\nfor (String a : apps) { System.out.println(a); }`,
    jdk: `public class Main {\n    public static void main(String[] args) {\n        System.out.println("JDK: " + System.getProperty("java.version"));\n    }\n}`,
    jre: `public class Main {\n    public static void main(String[] args) {\n        Runtime rt = Runtime.getRuntime();\n        System.out.println("Memory: " + rt.totalMemory());\n    }\n}`,
    jvm: `public class Main {\n    public static void main(String[] args) {\n        System.out.println(System.getProperty("java.vm.name"));\n    }\n}`,
    setup: `public class Main {\n    public static void main(String[] args) {\n        System.out.println("Environment ready.");\n    }\n}`,
    first_program: `public class Main {\n    public static void main(String[] args) {\n        System.out.println("Hello, World!");\n    }\n}`,
    variables: `int age = 20;\ndouble salary = 50000.50;\nString name = "Java Learner";\nSystem.out.println(name + " - " + age + " - " + salary);`,
    data_types: `int count = 100;\ndouble price = 99.99;\nchar grade = 'A';\nboolean active = true;\nString message = "Hello";`,
    operators: `int a = 10, b = 3;\nint sum = a + b;\nboolean isGreater = a > b;\nboolean andResult = (a > 5) && (b < 5);`,
    io: `Scanner sc = new Scanner(System.in);\nint num = sc.nextInt();\nSystem.out.println("You entered: " + num);`,
    comments: `// Single line comment\n/* Multi-line\n   comment */\n/** Javadoc comment */`,
    keywords: `// abstract, assert, boolean, break, byte, case, catch, char, class, const, continue\n// default, do, double, else, enum, extends, final, finally, float, for, goto\n// if, implements, import, instanceof, int, interface, long, native, new, package\n// private, protected, public, return, short, static, strictfp, super, switch\n// synchronized, this, throw, throws, transient, try, void, volatile, while`,
    conditionals: `int age = 20;\nif (age >= 18) {\n    System.out.println("Adult");\n} else {\n    System.out.println("Minor");\n}`,
    loops: `for (int i = 1; i <= 5; i++) {\n    System.out.println(i);\n}`,
    methods: `public static int add(int a, int b) {\n    return a + b;\n}`,
    arrays: `int[] numbers = {10, 20, 30, 40, 50};\nfor (int n : numbers) {\n    System.out.println(n);\n}`,
    classes: `class Student {\n    String name;\n    int age;\n    \n    Student(String name, int age) {\n        this.name = name;\n        this.age = age;\n    }\n}`,
    strings: `String str = "Hello";\nSystem.out.println(str.length());\nSystem.out.println(str.toUpperCase());`,
    exceptions: `try {\n    int result = 10 / 0;\n} catch (ArithmeticException e) {\n    System.out.println("Cannot divide by zero");\n}`,
    collections: `List<String> list = new ArrayList<>();\nlist.add("Java");\nlist.add("Python");\nfor (String lang : list) {\n    System.out.println(lang);\n}`,
    files: `BufferedReader reader = new BufferedReader(new FileReader("file.txt"));\nString line = reader.readLine();\nreader.close();`,
    threads: `Thread t = new Thread(() -> {\n    System.out.println("Running in thread");\n});\nt.start();`,
    lambdas: `List<Integer> nums = Arrays.asList(1, 2, 3, 4, 5);\nnums.stream().filter(n -> n % 2 == 0).forEach(System.out::println);`,
    spring: `@RestController\npublic class HelloController {\n    @GetMapping("/hello")\n    public String hello() {\n        return "Hello, Spring!";\n    }\n}`,
    spring_boot: `@SpringBootApplication\npublic class Application {\n    public static void main(String[] args) {\n        SpringApplication.run(Application.class, args);\n    }\n}`,
    jdbc: `Connection conn = DriverManager.getConnection(url, user, pass);\nStatement stmt = conn.createStatement();\nResultSet rs = stmt.executeQuery("SELECT * FROM users");`,
    sql: `CREATE TABLE users (\n    id INT PRIMARY KEY,\n    name VARCHAR(100),\n    email VARCHAR(100)\n);\nSELECT * FROM users WHERE id = 1;`,
    git: `git init\ngit add .\ngit commit -m "Initial commit"\ngit push origin main`,
    testing: `@Test\npublic void testAddition() {\n    assertEquals(5, calculator.add(2, 3));\n}`,
    project: `// Project structure will be defined in the project specification`,
  };

  return defaults[inferJavaKind(title)] || `public class Main {\n    public static void main(String[] args) {\n        System.out.println("Learning Java");\n    }\n}`;
};

