const buildJavaPracticeNotes = (entry, kind) => {
  const practiceSets = {
    intro: ['Write a simple Java program that prints your name and favorite programming language.', 'Modify the Hello World program to print multiple lines using separate println statements.'],
    history: ['Create an array of Java version milestones and print them with years.', 'Research the latest Java LTS release and add it to your knowledge.'],
    features: ['List 5 Java features and write a program that explains each one using print statements.', 'Compare Java features with another language you know.'],
    applications: ['Write a program that categorizes Java applications by domain type (mobile, web, enterprise, etc.).', 'Research a real company that uses Java and describe their tech stack.'],
    jdk: ['Write a program that displays all JDK tools and their purposes using arrays.', 'Run javac -version and java -version from the command line, then print the output.'],
    jre: ['Write a program that displays JRE components and their roles.', 'Explain the difference between JDK and JRE to someone new to programming.'],
    jvm: ['Write a program that displays JVM architecture components.', 'Use Runtime class to display memory and processor information.'],
    setup: ['Write a verification program that checks if Java is installed and displays version details.', 'Practice running javac and java commands from different directories.'],
    'IDE Setup': ['Write a program that displays the top 5 Java IDEs and their features.', 'Install an IDE and create your first project.'],
    'First Java Program': ['Write a complete Java program that prints your name, course, and favorite hobby.', 'Practice the compile-run cycle at least 5 times with small changes.'],
    variables: ['Declare variables of each primitive type and print them.', 'Experiment with variable scope by declaring variables inside and outside blocks.'],
    data_types: ['Create variables of each data type and print their values.', 'Experiment with integer overflow and floating-point precision.'],
    operators: ['Write expressions using each operator type and print results.', 'Predict output before running: System.out.println(10 + 5 * 2);'],
    io: ['Write a program that takes name, age, and salary as input and prints a formatted summary.', 'Handle the case where user enters text when a number is expected.'],
    comments: ['Add single-line, multi-line, and documentation comments to your first Java program.', 'Run javadoc on your commented file and view the generated HTML.'],
    keywords: ['List 10 Java keywords and write a short description for each.', 'Try using a keyword as a variable name and observe the compilation error.'],
    conditionals: ['Write a program that checks if a number is positive, negative, or zero.', 'Create a simple menu system using switch statement.'],
    loops: ['Print numbers 1 to 10 using each type of loop.', 'Create a multiplication table using nested loops.'],
    methods: ['Write a method that calculates factorial and test it with different inputs.', 'Create overloaded methods for calculating area of different shapes.'],
    arrays: ['Create an array of 5 integers, calculate sum and average.', 'Search for a specific value in an array and return its index.'],
    classes: ['Create a Student class with name, age, and grade fields. Create multiple Student objects.', 'Add a constructor and a method that displays student information.'],
    strings: ['Write a program that reverses a string and checks if it is a palindrome.', 'Count vowels and consonants in a user-provided string.'],
    exceptions: ['Write a program that handles division by zero gracefully.', 'Create a custom exception class and use it in a program.'],
    collections: ['Store a list of student names in an ArrayList and display them sorted.', 'Count word frequencies in a sentence using a HashMap.'],
    files: ['Write a program that reads a text file and counts the number of words.', 'Create a simple todo list that saves to and loads from a file.'],
    threads: ['Create two threads that print numbers 1-5 concurrently.', 'Use ExecutorService to run multiple tasks and get their results.'],
    lambdas: ['Convert a list of strings to uppercase using streams.', 'Filter even numbers from a list and collect them into a new list.'],
    sql: ['Write SQL queries to create tables, insert data, and retrieve results.', 'Write a query with JOIN to combine data from related tables.'],
    jdbc: ['Write a Java program that connects to a database and executes a SELECT query.', 'Implement a PreparedStatement to insert user data safely.'],
    git: ['Initialize a Git repository, make commits, and check the log.', 'Create a branch, make changes, and merge it back to main.'],
    spring: ['Create a Spring Boot application with a REST endpoint that returns "Hello, World!".', 'Use dependency injection to wire a service into a controller.'],
    testing: ['Write JUnit tests for a simple calculator class.', 'Use Mockito to mock a database repository in unit tests.'],
    project: ['Plan the project structure before writing any code.', 'Complete the mastery challenge for this topic to prove your understanding.'],
    general: ['Practice writing the example code from this topic yourself.', 'Explain the concept to a friend or write a summary in your own words.'],
  };

  return (practiceSets[kind] || practiceSets.general).join('\n');
};

const buildJavaTopicSections = (entry) => {
  const kind = inferJavaKind(entry.title);
  return {
    definition: buildJavaDefinition(entry, kind),
    explanation: buildJavaExplanation(entry, kind),
    syntax: getJavaSyntaxForTopic(entry.title),
    example: getJavaExampleForTopic(entry.title),
    notes: buildJavaNotes(kind),
    tip: buildJavaPracticeNotes(entry, kind),
  };
};

const buildJavaLearningMeta = (entry) => {
  if (!entry) return null;

  const kind = inferJavaKind(entry.title);
  const goalsByKind = {
    intro: ['Understand what Java is and why it is popular', 'Explain the Java platform architecture', 'Identify where Java is used in industry'],
    history: ['Trace the evolution of Java from Oak to modern releases', 'Understand how Java versions are numbered', 'Know key milestones in Java history'],
    features: ['List and explain the major features of Java', 'Understand platform independence through bytecode', 'Explain how Java achieves security and portability'],
    applications: ['Identify the major domains where Java is used', 'Understand Java role in enterprise and mobile development', 'Connect Java concepts to real-world applications'],
    jdk: ['Understand the tools included in JDK', 'Explain the purpose of javac, java, jar, javadoc', 'Distinguish between JDK and JRE'],
    jre: ['Understand JRE components and their roles', 'Explain how the ClassLoader works', 'Know the difference between JDK, JRE, and JVM'],
    jvm: ['Understand JVM architecture and components', 'Explain how bytecode execution works', 'Understand garbage collection basics'],
    setup: ['Install JDK correctly', 'Configure environment variables', 'Verify installation with command line tools'],
    first_program: ['Write a complete Java program', 'Understand the compile-run cycle', 'Identify the structure of a Java application'],
    variables: ['Declare and initialize variables correctly', 'Understand naming conventions and scope', 'Choose appropriate data types for different values'],
    data_types: ['Identify all primitive data types', 'Understand type conversion and casting', 'Use appropriate types for different scenarios'],
    operators: ['Use arithmetic, relational, and logical operators', 'Understand operator precedence', 'Write correct expressions'],
    io: ['Read user input using Scanner', 'Handle different input types correctly', 'Understand input validation basics'],
    conditionals: ['Write if, if-else, and nested if statements', 'Use switch for multi-way branching', 'Choose the right conditional for each situation'],
    loops: ['Use for, while, and do-while loops correctly', 'Understand break and continue', 'Choose the right loop for each task'],
    methods: ['Define and call methods', 'Understand parameters and return types', 'Use method overloading effectively'],
    arrays: ['Create and initialize arrays', 'Access and modify array elements', 'Use enhanced for loop for traversal'],
    classes: ['Define classes with fields and methods', 'Create objects using constructors', 'Understand reference vs primitive types'],
    strings: ['Use String class methods effectively', 'Choose between String, StringBuilder, and StringBuffer', 'Perform string comparisons correctly'],
    exceptions: ['Handle exceptions with try-catch-finally', 'Create custom exception classes', 'Understand checked vs unchecked exceptions'],
    collections: ['Choose the right collection for each use case', 'Use List, Set, and Map interfaces', 'Sort and search collections effectively'],
    files: ['Read from and write to files', 'Use buffered streams for performance', 'Understand serialization'],
    threads: ['Create and manage threads', 'Synchronize access to shared resources', 'Use Executor Framework for thread pools'],
    lambdas: ['Write lambda expressions', 'Use Streams API for data processing', 'Understand functional interfaces'],
    sql: ['Write SQL queries for CRUD operations', 'Use JOINs to combine tables', 'Understand aggregate functions and grouping'],
    jdbc: ['Connect Java applications to databases', 'Use PreparedStatement for safe queries', 'Manage transactions'],
    git: ['Use Git for version control', 'Create branches and merge changes', 'Understand GitHub workflow'],
    spring: ['Understand dependency injection', 'Create Spring beans', 'Build MVC applications'],
    spring_boot: ['Create Spring Boot applications', 'Build REST APIs', 'Use auto-configuration effectively'],
    testing: ['Write unit tests with JUnit', 'Use Mockito for mocking', 'Understand test-driven development'],
    project: ['Combine all concepts into an application', 'Follow clean code practices', 'Build portfolio-worthy projects'],
    general: ['Understand the concept clearly', 'Apply it in working Java code', 'Use it as a foundation for the next lesson'],
  };

  return {
    description: `${entry.title} helps you practice ${entry.description.toLowerCase()} inside a structured, end-to-end Java learning path.`,
    goals: goalsByKind[kind] || goalsByKind.general,
    practiceHint: buildJavaPracticeNotes(entry, kind).split('\n')[0],
    estimatedTime: `${entry.estimated_minutes} min`,
  };
};

export const isJavaProgrammingCourse = (courseId = '') =>
  courseId === 'java' || courseId === 'java-programming' || courseId === 'java-lang';

export const getJavaFallbackPhases = (courseId) =>
  isJavaProgrammingCourse(courseId)
    ? JAVA_PROGRAMMING_PHASES.map(({ topics, ...phase }) => ({ ...phase }))
    : [];

export const getJavaFallbackTopics = (phaseId) => {
  const phase = JAVA_PHASES_BY_ID.get(phaseId);
  return phase ? phase.topics.map((entry) => ({ ...entry, phase_id: phase.id })) : [];
};

export const getJavaFallbackTopicMetadata = (topicId) => JAVA_TOPICS_BY_ID.get(topicId) || null;

export const getJavaFallbackTopicLearningMeta = (topicId) =>
  buildJavaLearningMeta(getJavaFallbackTopicMetadata(topicId));

export const hasJavaFallbackTopicContent = (topicId) => JAVA_TOPICS_BY_ID.has(topicId);

export const getJavaFallbackTopicContent = (topicId) => {
  const entry = getJavaFallbackTopicMetadata(topicId);
  if (!entry) return [];
  if (entry.content_blocks) return entry.content_blocks;
  return buildJavaBlocks(topicId, buildJavaTopicSections(entry));
};
